#include <bits/stdc++.h>
using namespace std;
const int N=505;
int m,k,a[N],sum,ans[N],mx=-1;
bool check(int x)
{
    int cnt1=1,cnt2=0;
    for(int i=1;i<=m;i++)
    {
        cnt2+=a[i];
        if(cnt2>x)
        {
            cnt1++;
            cnt2=a[i];
            if(cnt1>k) return 0;
        }
    }
    return 1;
}
int main()
{
    cin>>m>>k;
    for(int i=1;i<=m;i++)
    {
        cin>>a[i];
        sum+=a[i];
        mx=max(mx,a[i]);
    }
    int l=mx,r=sum,mid;
    while(l<=r)
    {
        mid=(l+r)/2;
        if(check(mid)) r=mid-1;
        else l=mid+1;
    }
    int num=r+1,cnt1=k,cnt2=0;
    for(int i=m;i>0;i--)
    {
        cnt2+=a[i];
        if(cnt2>num)
        {
            cnt1--;
            ans[cnt1]=i;
            cnt2=a[i];
        }
    }
    ans[k]=m;
    for(int i=1;i<=k;i++)
    {
        cout<<ans[i-1]+1<<" "<<ans[i]<<'\n';
    }
    return 0;
}
